prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?seq) AS ?sequenceFlowCount)
WHERE {
  ?model a bboExt:Model .
  FILTER(
    STR(?model) = IRI(CONCAT("", "fbb0adafe6924f58ac902063a36646fe"))
  )
  OPTIONAL {
    ?model tai:normalizedId "fbb0adafe6924f58ac902063a36646fe" .
  }
  OPTIONAL {
    ?model tai:originalId "fbb0adafe6924f58ac902063a36646fe" .
  }
  FILTER(
    ?model tai:normalizedId "fbb0adafe6924f58ac902063a36646fe" ||
    ?model tai:originalId "fbb0adafe6924f58ac902063a36646fe"
  )
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?seq a bbo:SequenceFlow .
  ?seq tai:belongsTo ?choreo .
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?seq) AS ?sequenceFlowCount) (COUNT(DISTINCT ?choreo) AS ?choreoCount)
WHERE {
  ?model a bboExt:Model .
  {
    ?model tai:normalizedId "fbb0adafe6924f58ac902063a36646fe" .
  }
  UNION
  {
    ?model tai:originalId "fbb0adafe6924f58ac902063a36646fe" .
  }
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  {
    ?seq a bbo:SequenceFlow .
    ?seq tai:belongsTo ?choreo .
  }
}
